import React, { useEffect, useState } from "react";
import { auth, Namedb, provider } from "../components/firebase_setup";
import { signInWithPopup } from "firebase/auth";
import Home from "./Home";
import { useNavigate } from "react-router-dom";
import { collection, doc, getDocs, query, where } from "firebase/firestore";
import App from "../App";

//If I close the popup it crashes, so gotta do something abt that


function SignIn(){
    
    const[Value,setValue] = useState("");
    const navigate = useNavigate();

    const handlesignIn =()=>{
        signInWithPopup(auth, provider).then(async (data)=>{
            const u_email = data.user.email;
            setValue(u_email);
            localStorage.setItem("email", u_email);

            const Pcol = collection(Namedb, "ProfileData");
            const query = query(Pcol, where("email", "==", u_email));
            const Pdata = await getDocs(query);

            if(!Pdata.empty){
                navigate("/feed");
            }else{
                navigate("/home");
            }
        }).catch((error) => {
            console.error("Failed to Sign in", error);
        });
    }

    useEffect(()=>{
        setValue(localStorage.getItem('email'))
    },[])

    return(
        <div className="signin_body">
            <h1 className="header">Welcome to Catsa. To continue Please use your Google account to log in.</h1>
            {Value ? <Home/> :
            <button className="SigninButton" onClick={handlesignIn}>Sign In With Google</button>
            }
        </div>
    );
}

export default SignIn;
